css_p2:
#sec-01 .surface{position: relative; padding: var(--section-pad) 0; overflow: hidden;}
#sec-01 .surface--dark{background: var(--bg-dark); color: var(--text-on-dark);}
#sec-01 .h1{font-size: 48px; line-height: 1.08; font-weight: 500; letter-spacing: -0.02em; margin: 0px;}
#sec-01 .mono-label{font-family: var(--font-mono); font-size: 12px; font-weight: 400; letter-spacing: 0.12em; text-transform: lowercase;}
#sec-01 .mono-tag{font-family: var(--font-mono); font-size: 11px; font-weight: 400; letter-spacing: 0.04em; text-transform: lowercase;}
#sec-01 .wordmark{font-family: var(--font-sans); font-weight: 500; font-size: 22px; letter-spacing: -0.015em; line-height: 1;}
#sec-01 .wordmark .sof{color: var(--accent-amber);}
#sec-01 .wordmark-mark{display: inline-flex; align-items: center; justify-content: center; width: 32px; height: 32px; border: 1px solid; border-radius: var(--r-sm); font-family: var(--font-sans); font-weight: 500; font-size: 18px; letter-spacing: -0.02em;}
#sec-01 .wordmark-mark .s{color: var(--accent-amber);}
#sec-01 .page-header{display: flex; align-items: center; justify-content: space-between; padding: 22px 0px; gap: 24px;}
#sec-01 .page-header .nav{display: flex; gap: 28px; align-items: center;}
#sec-01 .page-header .nav a{color: var(--text-on-dark); text-decoration: none; font-family: var(--font-mono); font-size: 12px; letter-spacing: 0.08em; transition: color 200ms var(--ease);}
#sec-01 .page-header .nav a:hover{color: var(--accent-amber);}
#sec-01 .row{display: flex; gap: 16px; align-items: center; flex-wrap: wrap;}
#sec-01 .stack{display: flex; flex-direction: column;}
#sec-01 .btn--ghost-dark{background: transparent; color: var(--text-on-dark); border-color: var(--border-dark-strong);}
#sec-01 .btn--ghost-dark:hover{transform: translateY(-1px); border-color: var(--text-on-dark);}
#sec-01 .btn .ti{font-size: 14px;}
#sec-01 .tag{display: inline-flex; align-items: center; gap: 6px; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.04em; text-transform: lowercase; padding: 4px 9px; border-radius: var(--r-sm); border: 1px solid var(--border-dark-strong); background: transparent; line-height: 1.2; color: var(--muted-on-dark);}
#sec-01 .tag--status{color: var(--accent-amber); border-color: rgba(239, 159, 39, 0.45); background: rgba(239, 159, 39, 0.08);}
#sec-01 .inline-select{display: inline-flex; align-items: baseline; gap: 6px; border-bottom: 1px dashed var(--accent-amber); color: var(--accent-amber); font: inherit; padding: 0px 4px; cursor: pointer; position: relative;}
#sec-01 .inline-select select{background: transparent; border: 0px; color: inherit; font: inherit; padding: 0px 16px 0px 0px; cursor: pointer; appearance: none; letter-spacing: inherit;}
#sec-01 .inline-select select option{color: var(--text-on-light); background: var(--bg-cream);}
#sec-01 .inline-select .ti{font-size: 0.55em; opacity: 0.85; position: absolute; right: 2px; top: 50%; transform: translateY(-40%); pointer-events: none;}
#sec-01 .inline-select:hover{border-bottom-color: var(--accent-amber-2);}
#sec-01 .hero-scrub{position: relative; height: 200vh; background: var(--bg-dark);}
#sec-01 .hero-sticky{position: sticky; top: 0px; height: 100vh; width: 100%; overflow: hidden;}
#sec-01 #hero-video{position: absolute; inset: 0px; width: 100%; height: 100%; object-fit: cover; object-position: center center; background: rgb(19, 18, 26); will-change: opacity;}
#sec-01 .hero-header-overlay{position: absolute; top: 0px; left: 0px; right: 0px; z-index: 10; transition: background-color 240ms var(--ease), backdrop-filter 240ms var(--ease), border-color 240ms var(--ease); border-bottom: 1px solid transparent;}
body.hero-scrolled .hero-header-overlay{background: rgba(19, 18, 26, 0.5); backdrop-filter: blur(12px); border-bottom-color: var(--border-dark);}
#sec-01 .hero-headline{position: absolute; top: 18%; left: 0px; right: 0px; z-index: 5; text-align: center; padding: 0 var(--pad); pointer-events: none; will-change: opacity, transform;}
#sec-01 .hero-headline .h1-display{color: var(--text-on-dark); text-shadow: rgba(0, 0, 0, 0.4) 0px 2px 24px; max-width: 980px; margin: 0px auto; text-wrap: balance;}
#sec-01 .hero-headline .body-lg{margin-top: 14px; color: rgba(245, 241, 232, 0.78); text-shadow: rgba(0, 0, 0, 0.4) 0px 2px 24px;}
#sec-01 .scroll-cue{position: absolute; bottom: 32px; left: 50%; transform: translateX(-50%); z-index: 5; display: inline-flex; align-items: center; gap: 8px; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.12em; text-transform: lowercase; color: rgba(245, 241, 232, 0.7); text-shadow: rgba(0, 0, 0, 0.4) 0px 2px 24px; pointer-events: none; will-change: opacity;}
#sec-01 .scroll-cue .ti{font-size: 14px;}
#sec-01 .configurator-section{position: relative; padding: calc(var(--section-pad) + 40px) 0 var(--section-pad) 0; background: var(--bg-dark); color: var(--text-on-dark); overflow: hidden;}
#sec-01 .configurator-section::before{content: ""; position: absolute; top: 0px; left: 50%; width: 600px; height: 300px; transform: translate(-50%, -50%); background: radial-gradient(rgba(239, 159, 39, 0.05) 0%, transparent 60%); filter: blur(20px); pointer-events: none; z-index: 0;}
#sec-01 .configurator-section .inner{max-width: 980px; margin: 0px auto; padding: 0 var(--pad); display: flex; flex-direction: column; gap: 40px; position: relative; z-index: 1;}
#sec-01 .configurator-section .inner > *{opacity: 0; transform: translateY(12px); transition: opacity 600ms var(--ease), transform 600ms var(--ease);}
#sec-01 .configurator-section.is-revealed .inner > :nth-child(1){opacity: 1; transform: none; transition-delay: 0ms;}
#sec-01 .configurator-section.is-revealed .inner > :nth-child(2){opacity: 1; transform: none; transition-delay: 80ms;}
#sec-01 .configurator-section.is-revealed .inner > :nth-child(3){opacity: 1; transform: none; transition-delay: 160ms;}
#sec-01 .configurator{font-size: 44px; line-height: 1.18; font-weight: 500; letter-spacing: -0.02em; color: var(--text-on-dark); text-wrap: balance; margin: 0px;}
#sec-01 .configurator .inline-select{font: inherit; color: var(--accent-amber);}
#sec-01 .configurator .inline-select select{font: inherit;}
#sec-01 .response{border-top: 1px dashed var(--border-dark); padding-top: 32px; display: flex; flex-direction: column; gap: 22px; text-align: left; transition: opacity 140ms var(--ease);}
#sec-01 .response.updating{opacity: 0.5;}
#sec-01 .response-eyebrow{display: inline-flex; align-items: center; gap: 10px; font-family: var(--font-mono); font-size: 12px; font-weight: 400; letter-spacing: 0.1em; text-transform: lowercase; color: var(--muted-on-dark);}
#sec-01 .response-eyebrow::before{content: ""; width: 6px; height: 6px; border-radius: 50%; background: var(--accent-amber); display: inline-block;}
#sec-01 .response-copy{color: var(--text-on-dark); max-width: 760px;}
#sec-01 .response-tags{display: flex; flex-wrap: wrap; gap: 8px; align-items: center;}
#sec-01 .response-status{display: flex; flex-wrap: wrap; gap: 8px; align-items: center;}
#sec-01 .response-cta-row{display: flex; gap: 12px; flex-wrap: wrap; padding-top: 6px; align-items: center;}
#sec-01 .section-3{min-height: 100vh; display: flex; align-items: center;}
#sec-01 .section-3 .inner{max-width: 980px; padding: 0 var(--pad); margin: 0px auto; display: flex; flex-direction: column; gap: 24px;}
@media (max-width: 900px){
:root { --section-pad: 72px; --pad: 20px; }
#sec-01 .h1-display{font-size: 36px;}
#sec-01 .h1{font-size: 28px;}
#sec-01 .h2{font-size: 22px;}
#sec-01 .configurator{font-size: 26px;}
#sec-01 .hero-scrub{height: auto;}
#sec-01 .hero-sticky{position: static; height: auto; min-height: 70vh;}
#sec-01 #hero-video{display: none;}
#sec-01 .hero-end-poster{display: none;}
#sec-01 .hero-mobile-poster{display: block; width: 100%; height: auto; aspect-ratio: 16 / 9; object-fit: cover;}
#sec-01 .hero-headline{position: static; padding: 32px 20px 24px; text-align: left;}
#sec-01 .hero-headline .h1-display, #sec-01 .hero-headline .body-lg{text-shadow: none;}
#sec-01 .hero-headline .h1-display{margin: 0px; max-width: none;}
#sec-01 .scroll-cue{display: none;}
#sec-01 .page-header .nav{display: none;}
#sec-01 .hero-header-overlay{position: static;}
body.hero-scrolled .hero-header-overlay{background: transparent; backdrop-filter: none; border-bottom-color: transparent;}
}
#sec-01 .hero-mobile-poster{display: none;}

css_p3:
#sec-02 .leadin{min-height: 64vh; display: flex; align-items: flex-end; padding: 0 0 var(--section-pad); position: relative; background: var(--bg-dark);}
#sec-02 .leadin .inner{max-width: 980px; margin: 0px auto; padding: 0 var(--pad);}
#sec-02 .leadin .body-lg{color: var(--muted-on-dark); max-width: 640px; margin-top: 14px;}
#sec-02 .showcase{position: relative; height: 400vh; background: var(--bg-dark);}
#sec-02 .showcase-sticky{position: sticky; top: 0px; height: 100vh; display: flex; align-items: stretch; overflow: hidden;}
#sec-02 .showcase-rail{width: 34%; flex: 0 0 auto; display: flex; flex-direction: column; justify-content: center; padding: 0 48px 0 max(var(--pad), calc((100vw - var(--container)) / 2 + var(--pad))); position: relative; z-index: 2; opacity: 0; transform: translateX(-20px); transition: opacity 600ms var(--ease) 120ms, transform 600ms var(--ease) 120ms;}
#sec-02 .showcase-entered .showcase-rail{opacity: 1; transform: none;}
#sec-02 .rail-eyebrow{margin-bottom: 20px;}
#sec-02 .rail-h2{max-width: 340px; margin-bottom: 30px; color: var(--text-on-dark); font-size: 28px;}
#sec-02 .rail-list{list-style: none; margin: 0px; padding: 0px; position: relative; display: flex; flex-direction: column;}
#sec-02 .rail-line, #sec-02 .rail-fill{position: absolute; left: 14px; width: 2px; border-radius: 2px;}
#sec-02 .rail-line{top: 16px; bottom: 16px; background: var(--border-dark-strong);}
#sec-02 .rail-fill{top: 16px; height: 0px; background: var(--accent-amber); transition: height 180ms linear; z-index: 1;}
#sec-02 .rail-item{position: relative; z-index: 2; display: grid; grid-template-columns: 30px 1fr; gap: 16px; align-items: start; padding: 13px 12px 13px 0px; cursor: pointer; border-radius: 10px; transition: background 300ms var(--ease);}
#sec-02 .rail-item .ri-num{position: relative; z-index: 1; width: 30px; height: 30px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-family: var(--font-mono); font-size: 12px; font-weight: 700; color: var(--muted-on-dark); background: var(--bg-dark); border: 1.5px solid var(--border-dark-strong); transition: color 280ms var(--ease), background 280ms var(--ease), border-color 280ms var(--ease);}
#sec-02 .ri-label{font-size: 19px; font-weight: 500; letter-spacing: -0.01em; color: var(--muted-on-dark); transition: color 280ms var(--ease); line-height: 1.1; padding-top: 4px;}
#sec-02 .ri-desc{font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.03em; text-transform: lowercase; color: var(--muted-on-dark); opacity: 0.45; margin-top: 7px; transition: opacity 280ms var(--ease); line-height: 1.5;}
#sec-02 .ri-chips{display: flex; flex-wrap: wrap; gap: 6px; max-height: 0px; opacity: 0; overflow: hidden; margin-top: 0px; transition: max-height 300ms var(--ease), opacity 280ms var(--ease), margin-top 300ms var(--ease);}
#sec-02 .ri-chip{font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.01em; padding: 4px 9px; border-radius: var(--r-pill); border: 1px solid var(--border-dark); color: var(--muted-on-dark); white-space: nowrap;}
#sec-02 .rail-item:hover .ri-label{color: var(--text-on-dark);}
#sec-02 .rail-item.active{background: linear-gradient(90deg, rgba(239, 159, 39, 0.06), transparent 80%);}
#sec-02 .rail-item.active .ri-num{color: rgb(26, 26, 26); background: var(--accent-amber); border-color: var(--accent-amber);}
#sec-02 .rail-item.active .ri-label{color: var(--text-on-dark);}
#sec-02 .rail-item.active .ri-desc{opacity: 0.85;}
#sec-02 .rail-item.active .ri-chips{max-height: 48px; opacity: 1; margin-top: 12px;}
#sec-02 .rail-caption{margin-top: 30px; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.08em; text-transform: lowercase; color: var(--muted-on-dark); display: inline-flex; align-items: center; gap: 8px;}
#sec-02 .showcase-stage{width: 66%; flex: 1 1 0%; position: relative; display: flex; align-items: center; justify-content: center; padding: 0 max(var(--pad), calc((100vw - var(--container)) / 2 + var(--pad))) 0 0; transform: translateX(-26%) scale(0.72); transform-origin: center center; transition: transform 640ms var(--ease);}
#sec-02 .showcase-entered .showcase-stage{transform: none;}
#sec-02 .stage-frames{position: relative; width: 100%; max-width: 760px; height: 580px;}
#sec-02 .stage-demo{position: absolute; inset: 0px; display: flex; flex-direction: column; gap: 14px; opacity: 0; pointer-events: none; transform: translateY(8px); transition: opacity 400ms var(--ease), transform 400ms var(--ease);}
#sec-02 .stage-demo.active{opacity: 1; pointer-events: auto; transform: none;}
#sec-02 .demo-mobile-head{display: none;}
#sec-02 .frame{flex: 1 1 0%; min-height: 0px; display: flex; flex-direction: column; background: var(--bg-dark-2); border: 1px solid var(--border-dark); border-radius: var(--r-lg); overflow: hidden; box-shadow: rgba(0, 0, 0, 0.7) 0px 24px 60px -30px;}
#sec-02 .chrome{flex: 0 0 auto; display: flex; align-items: center; gap: 14px; padding: 0px 14px; height: 38px; border-bottom: 1px solid var(--border-dark); background: rgba(0, 0, 0, 0.18);}
#sec-02 .chrome-dots{display: flex; gap: 7px;}
#sec-02 .chrome-dots i{width: 10px; height: 10px; border-radius: 50%; background: var(--border-dark-strong);}
#sec-02 .chrome-url{flex: 1 1 0%; display: flex; align-items: center; gap: 7px; height: 22px; padding: 0px 12px; background: rgba(0, 0, 0, 0.25); border-radius: var(--r-pill); font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.02em; color: var(--muted-on-dark); max-width: 280px;}
#sec-02 .chrome-url i{font-size: 11px; color: var(--accent-indigo-2);}
#sec-02 .frame-body{flex: 1 1 0%; min-height: 0px; position: relative; overflow: hidden;}
#sec-02 .demo-caption{flex: 0 0 auto; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.06em; text-transform: lowercase; color: var(--muted-on-dark); display: inline-flex; align-items: center; gap: 8px; padding-left: 2px;}
#sec-02 .demo-caption::before{content: "↳"; color: var(--accent-amber);}
#sec-02 .livedot{display: inline-block; width: 7px; height: 7px; border-radius: 50%; background: var(--pos); position: relative;}
#sec-02 .livedot.loop::after{content: ""; position: absolute; inset: 0px; border-radius: 50%; background: var(--pos); animation: livepulse 2.2s var(--ease) infinite;}
@keyframes livepulse { 
  0% { transform: scale(1); opacity: 0.55; }
  70% { transform: scale(3); opacity: 0; }
  100% { transform: scale(3); opacity: 0; }
}
#sec-02 .live-tag{display: inline-flex; align-items: center; gap: 7px; font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.06em; text-transform: lowercase; color: var(--muted-on-dark);}
#sec-02 .scrollarea{height: 100%; overflow: auto; scrollbar-width: thin; scrollbar-color: var(--border-dark-strong) transparent;}
#sec-02 .scrollarea::-webkit-scrollbar{width: 7px;}
#sec-02 .scrollarea::-webkit-scrollbar-thumb{background: var(--border-dark-strong); border-radius: 4px;}
#sec-02 .demo-toast{position: absolute; left: 50%; bottom: 16px; transform: translate(-50%, 20px); background: var(--bg-dark); border: 1px solid var(--border-dark-strong); border-radius: var(--r-pill); padding: 9px 16px; z-index: 20; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.02em; color: var(--text-on-dark); box-shadow: rgba(0, 0, 0, 0.8) 0px 16px 40px -18px; opacity: 0; pointer-events: none; white-space: nowrap; transition: opacity 300ms var(--ease), transform 300ms var(--spring); display: inline-flex; align-items: center; gap: 9px; max-width: 90%;}
#sec-02 .demo-toast.show{opacity: 1; transform: translate(-50%, 0px);}
#sec-02 .demo-toast .ti{color: var(--pos); font-size: 14px;}
#sec-02 .coach{position: relative;}
#sec-02 .coach::after{content: ""; position: absolute; inset: -4px; border-radius: inherit; border: 2px solid var(--accent-amber); box-shadow: rgba(239, 159, 39, 0.1) 0px 0px 0px 4px; animation: coachPulse 1.8s var(--ease) infinite; pointer-events: none; z-index: 4;}
@keyframes coachPulse { 
  0%, 100% { opacity: 0.4; }
  50% { opacity: 1; }
}
#sec-02 .coach-tip{position: absolute; bottom: calc(100% + 10px); left: 50%; transform: translateX(-50%); white-space: nowrap; font-family: var(--font-mono); font-size: 10px; font-weight: 700; letter-spacing: 0.03em; text-transform: lowercase; background: var(--accent-amber); color: rgb(26, 26, 26); padding: 5px 10px; border-radius: var(--r-pill); box-shadow: rgba(0, 0, 0, 0.7) 0px 8px 20px -8px; z-index: 32; pointer-events: none; animation: coachFloat 2s var(--ease) infinite;}
#sec-02 .coach-tip::after{content: ""; position: absolute; top: 100%; left: 50%; transform: translateX(-50%); border-width: 5px; border-style: solid; border-right-color: transparent; border-bottom-color: transparent; border-left-color: transparent; border-image: initial; border-top-color: var(--accent-amber);}
#sec-02 .coach-tip.out{opacity: 0; transition: opacity 350ms var(--ease);}
@keyframes coachFloat { 
  0%, 100% { transform: translateX(-50%) translateY(0px); }
  50% { transform: translateX(-50%) translateY(-4px); }
}
#sec-02 .bank{display: flex; height: 100%;}
#sec-02 .bank-side{flex: 0 0 auto; width: 168px; border-right: 1px solid var(--border-dark); padding: 18px 14px; display: flex; flex-direction: column; gap: 4px;}
#sec-02 .bank-side .brand{display: flex; align-items: center; gap: 9px; padding: 4px 8px 18px; font-weight: 500; font-size: 14px;}
#sec-02 .bank-side .brand .mk{width: 22px; height: 22px; border-radius: 6px; flex: 0 0 auto; background: var(--accent-indigo); display: flex; align-items: center; justify-content: center; color: rgb(255, 255, 255); font-size: 12px; font-weight: 500;}
#sec-02 .bank-nav{display: flex; align-items: center; gap: 11px; padding: 9px 10px; border-radius: var(--r-md); font-size: 13.5px; color: var(--muted-on-dark); cursor: pointer; transition: background 180ms var(--ease), color 180ms var(--ease);}
#sec-02 .bank-nav i{font-size: 16px;}
#sec-02 .bank-nav:hover{color: var(--text-on-dark);}
#sec-02 .bank-nav.active{background: rgba(124, 108, 255, 0.14); color: var(--accent-indigo-2);}
#sec-02 .bank-main{flex: 1 1 0%; min-width: 0px; padding: 20px 22px; overflow: auto;}
#sec-02 .bank-balance{border: 1px solid var(--border-dark); border-radius: var(--r-md); padding: 16px 18px 14px; margin-bottom: 18px; background: rgba(124, 108, 255, 0.05); display: flex; flex-direction: column; gap: 12px;}
#sec-02 .bal-top{display: flex; align-items: flex-start; justify-content: space-between; gap: 16px;}
#sec-02 .bank-balance .lbl{font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.08em; text-transform: lowercase; color: var(--muted-on-dark); display: inline-flex; align-items: center; gap: 8px;}
#sec-02 .bank-balance .amt{font-family: var(--font-mono); font-size: 28px; font-weight: 700; letter-spacing: -0.01em; margin-top: 6px; color: var(--text-on-dark);}
#sec-02 .bank-balance .delta{font-family: var(--font-mono); font-size: 11px; color: var(--pos); margin-top: 5px; display: inline-flex; align-items: center; gap: 4px;}
#sec-02 .bank-balance .delta i{font-size: 13px;}
#sec-02 .bank-move{flex: 0 0 auto; display: inline-flex; align-items: center; gap: 8px; background: var(--accent-indigo); color: rgb(255, 255, 255); border-width: medium; border-style: none; border-color: currentcolor; border-image: initial; border-radius: var(--r-pill); font-family: var(--font-sans); font-weight: 500; font-size: 13px; padding: 9px 15px; cursor: pointer; transition: background 180ms var(--ease), transform 180ms var(--ease);}
#sec-02 .bank-move:hover{background: var(--accent-indigo-2); transform: translateY(-1px);}
#sec-02 .sparkline{width: 100%; height: 38px; display: block;}
#sec-02 .sparkline path.ln{fill: none; stroke: var(--accent-indigo); stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; stroke-dasharray: 360; stroke-dashoffset: 360;}
#sec-02 .sparkline.drawn path.ln{stroke-dashoffset: 0; transition: stroke-dashoffset 1000ms var(--ease);}
#sec-02 .sparkline path.area{fill: rgba(124, 108, 255, 0.1); opacity: 0; transition: opacity 600ms var(--ease) 400ms;}
#sec-02 .sparkline.drawn path.area{opacity: 1;}
#sec-02 .bank-txns-h{font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.08em; text-transform: lowercase; color: var(--muted-on-dark); margin-bottom: 6px; display: flex; align-items: center; justify-content: space-between;}
#sec-02 .txn{display: flex; align-items: center; gap: 13px; padding: 11px 12px; border-radius: var(--r-md); cursor: pointer; border: 1px solid transparent; transition: background 160ms var(--ease), border-color 160ms var(--ease);}
#sec-02 .txn:hover{background: rgba(245, 244, 249, 0.04);}
#sec-02 .txn.sel{background: rgba(124, 108, 255, 0.1); border-color: rgba(124, 108, 255, 0.35);}
#sec-02 .txn.new{animation: txnIn 460ms var(--ease);}
@keyframes txnIn { 
  0% { opacity: 0; transform: translateY(-10px); }
  100% { opacity: 1; transform: none; }
}
#sec-02 .txn .ic{width: 34px; height: 34px; border-radius: 9px; flex: 0 0 auto; display: flex; align-items: center; justify-content: center; background: rgba(245, 244, 249, 0.06); color: var(--text-on-dark); font-size: 16px; position: relative;}
#sec-02 .txn .ic.flag{background: rgba(239, 159, 39, 0.12); color: var(--accent-amber);}
#sec-02 .txn .who{flex: 1 1 0%; min-width: 0px;}
#sec-02 .txn .who b{font-weight: 500; font-size: 14px; display: flex; align-items: center; gap: 7px;}
#sec-02 .txn .who .ft{font-family: var(--font-mono); font-size: 8.5px; letter-spacing: 0.06em; text-transform: uppercase; color: var(--accent-amber); border: 1px solid rgba(239, 159, 39, 0.4); border-radius: 3px; padding: 1px 4px;}
