#sec-02 .shop-cart.open{transform: none;}
#sec-02 .cart-h{flex: 0 0 auto; padding: 18px 20px 12px; display: flex; align-items: center; justify-content: space-between; border-bottom: 1px solid var(--border-dark);}
#sec-02 .cart-h .ct{font-size: 15px; font-weight: 500;}
#sec-02 .cart-close{background: none; border-width: medium; border-style: none; border-color: currentcolor; border-image: initial; color: var(--muted-on-dark); cursor: pointer; font-size: 18px; line-height: 1; padding: 0px;}
#sec-02 .cart-close:hover{color: var(--text-on-dark);}
#sec-02 .cart-items{flex: 1 1 0%; min-height: 0px; overflow: auto; padding: 8px 20px;}
#sec-02 .cart-empty{color: var(--muted-on-dark); font-family: var(--font-mono); font-size: 11px; text-align: center; padding: 40px 0px; letter-spacing: 0.04em;}
#sec-02 .ci{display: flex; align-items: center; gap: 12px; padding: 11px 0px; border-bottom: 1px solid var(--border-dark); animation: txnIn 300ms var(--ease);}
#sec-02 .ci .img{width: 40px; height: 48px; border-radius: 7px; flex: 0 0 auto; overflow: hidden; background: rgba(245, 244, 249, 0.04);}
#sec-02 .ci .img img{width: 100%; height: 100%; object-fit: cover; display: block;}
#sec-02 .ci .nm{flex: 1 1 0%; min-width: 0px; font-size: 13px;}
#sec-02 .ci .nm span{display: block; font-family: var(--font-mono); font-size: 10px; color: var(--muted-on-dark);}
#sec-02 .ci .qp{font-family: var(--font-mono); font-size: 12.5px; font-weight: 700;}
#sec-02 .cart-foot{flex: 0 0 auto; padding: 14px 20px; border-top: 1px solid var(--border-dark); display: flex; flex-direction: column; gap: 12px;}
#sec-02 .ship{display: flex; flex-direction: column; gap: 7px;}
#sec-02 .ship-msg{font-family: var(--font-mono); font-size: 9.5px; letter-spacing: 0.03em; text-transform: lowercase; color: var(--muted-on-dark);}
#sec-02 .ship-msg.ok{color: var(--pos);}
#sec-02 .ship-bar{height: 4px; border-radius: 3px; background: rgba(245, 244, 249, 0.1); overflow: hidden;}
#sec-02 .ship-fill{display: block; height: 100%; width: 0px; background: var(--accent-indigo); border-radius: 3px; transition: width 450ms var(--ease);}
#sec-02 .ship-fill.ok{background: var(--pos);}
#sec-02 .cart-total{display: flex; align-items: baseline; justify-content: space-between;}
#sec-02 .cart-total .tl{font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.06em; text-transform: lowercase; color: var(--muted-on-dark);}
#sec-02 .cart-total .tv{font-family: var(--font-mono); font-size: 22px; font-weight: 700;}
#sec-02 .checkout{width: 100%; background: var(--accent-indigo); color: rgb(255, 255, 255); border-width: medium; border-style: none; border-color: currentcolor; border-image: initial; border-radius: var(--r-pill); font-family: var(--font-sans); font-weight: 500; font-size: 14px; padding: 12px; cursor: pointer; transition: background 180ms var(--ease);}
#sec-02 .checkout:hover{background: var(--accent-indigo-2);}
#sec-02 .shop-detail{position: absolute; inset: 0px; z-index: 12; background: rgba(8, 6, 14, 0.74); display: flex; align-items: center; justify-content: center; padding: 22px; opacity: 0; pointer-events: none; transition: opacity 280ms var(--ease);}
#sec-02 .shop-detail.open{opacity: 1; pointer-events: auto;}
#sec-02 .detail-card{width: 100%; max-width: 520px; background: var(--bg-dark-2); border: 1px solid var(--border-dark-strong); border-radius: var(--r-lg); overflow: hidden; display: grid; grid-template-columns: 44% 1fr; transform: scale(0.9); transition: transform 340ms var(--spring); box-shadow: rgba(0, 0, 0, 0.88) 0px 34px 80px -26px;}
#sec-02 .shop-detail.open .detail-card{transform: none;}
#sec-02 .detail-img{position: relative; background: rgba(245, 244, 249, 0.04);}
#sec-02 .detail-img img{width: 100%; height: 100%; object-fit: cover; display: block;}
#sec-02 .detail-info{padding: 20px; display: flex; flex-direction: column; gap: 11px; position: relative;}
#sec-02 .detail-close{position: absolute; top: 12px; right: 12px; width: 28px; height: 28px; border-radius: 7px; border: 1px solid var(--border-dark); background: rgba(0, 0, 0, 0.3); color: var(--muted-on-dark); cursor: pointer; display: flex; align-items: center; justify-content: center; transition: color 150ms var(--ease), border-color 150ms var(--ease);}
#sec-02 .detail-close:hover{color: var(--text-on-dark); border-color: var(--border-dark-strong);}
#sec-02 .detail-name{font-size: 18px; font-weight: 500; padding-right: 32px; line-height: 1.2;}
#sec-02 .detail-rate{font-family: var(--font-mono); font-size: 11px; color: var(--muted-on-dark); margin-top: 4px;}
#sec-02 .detail-price{font-family: var(--font-mono); font-size: 22px; font-weight: 700;}
#sec-02 .detail-desc{font-size: 12.5px; color: var(--muted-on-dark); line-height: 1.5; margin: 0px;}
#sec-02 .detail-sizes-l{font-family: var(--font-mono); font-size: 9.5px; letter-spacing: 0.06em; text-transform: lowercase; color: var(--muted-on-dark); margin-bottom: 7px;}
#sec-02 .detail-sizes{display: flex; gap: 6px;}
#sec-02 .dsize{width: 34px; height: 32px; border-radius: var(--r-sm); border: 1px solid var(--border-dark); background: rgba(0, 0, 0, 0.2); color: var(--muted-on-dark); font-family: var(--font-mono); font-size: 11px; cursor: pointer; display: flex; align-items: center; justify-content: center; transition: all 150ms var(--ease);}
#sec-02 .dsize:hover{border-color: var(--border-dark-strong); color: var(--text-on-dark);}
#sec-02 .dsize.sel{border-color: var(--accent-indigo); background: rgba(124, 108, 255, 0.15); color: var(--accent-indigo-2);}
#sec-02 .detail-add{margin-top: auto; background: var(--accent-indigo); color: rgb(255, 255, 255); border-width: medium; border-style: none; border-color: currentcolor; border-image: initial; border-radius: var(--r-pill); font-family: var(--font-sans); font-weight: 500; font-size: 14px; padding: 12px; cursor: pointer; transition: background 180ms var(--ease);}
#sec-02 .detail-add:hover{background: var(--accent-indigo-2);}
@media (max-width: 900px){
:root { --section-pad: 72px; --pad: 20px; }
#sec-02 .h1-display{font-size: 34px;}
#sec-02 .h2{font-size: 24px;}
#sec-02 .leadin{min-height: 40vh;}
#sec-02 .showcase{height: auto;}
#sec-02 .showcase-sticky{position: static; height: auto; display: block; overflow: visible;}
#sec-02 .showcase-rail{display: none;}
#sec-02 .showcase-stage{width: 100%; padding: 0 var(--pad); display: block; transform: none !important;}
#sec-02 .stage-frames{max-width: none; height: auto; padding: 8px 0 var(--section-pad);}
#sec-02 .stage-demo{position: static; inset: auto; margin-bottom: 64px; opacity: 1 !important; pointer-events: auto !important; transform: none !important;}
#sec-02 .demo-mobile-head{display: block; margin-bottom: 16px;}
#sec-02 .demo-mobile-head .eyebrow{margin-bottom: 8px;}
#sec-02 .demo-mobile-head .desc{color: var(--muted-on-dark); max-width: 460px;}
#sec-02 .frame{height: 560px;}
#sec-02 .chrome-url{max-width: none;}
#sec-02 .bank{flex-direction: column;}
#sec-02 .bank-side{width: 100%; flex-direction: row; align-items: center; gap: 4px; border-right-width: medium; border-right-style: none; border-right-color: currentcolor; border-bottom: 1px solid var(--border-dark); padding: 10px; overflow-x: auto;}
#sec-02 .bank-side .brand{display: none;}
#sec-02 .bank-nav{padding: 8px 12px; white-space: nowrap;}
#sec-02 .bank-drawer{width: 84%;}
#sec-02 .school-grid{grid-template-columns: repeat(3, 1fr);}
#sec-02 .shop-grid{grid-template-columns: repeat(2, 1fr);}
#sec-02 .shop-cart{width: 86%;}
#sec-02 .detail-card{grid-template-columns: 1fr; max-width: 320px;}
#sec-02 .detail-img{height: 200px;}
}
@media (max-width: 560px){
#sec-02 .school-grid{grid-template-columns: repeat(2, 1fr);}
}
@media (prefers-reduced-motion: reduce){
#sec-02 .livedot.loop::after{animation: auto ease 0s 1 normal none running none !important;}
#sec-02 .txn.new, #sec-02 .stu.flip, #sec-02 .cart-badge.pop, #sec-02 .floor-pop.open, #sec-02 .ci, #sec-02 .school-save.saved .ripple{animation: auto ease 0s 1 normal none running none !important;}
#sec-02 .table[data-state="open"], #sec-02 .table.cue::after, #sec-02 .cue-label{animation: auto ease 0s 1 normal none running none !important;}
#sec-02 .coach::after, #sec-02 .coach-tip{animation: auto ease 0s 1 normal none running none !important;}
}

css_p4:
#sec-03 .btn--ghost{background: transparent; color: var(--text-on-dark); border-color: var(--border-dark-strong);}
#sec-03 .btn--ghost:hover{transform: translateY(-1px); border-color: var(--text-on-dark);}
#sec-03 .btn .ti{font-size: 15px;}
#sec-03 .leadin{min-height: 52vh; display: flex; align-items: flex-end; padding: 0 0 var(--section-pad); position: relative; background: var(--bg-dark);}
#sec-03 .leadin .inner{max-width: 980px; margin: 0px auto; padding: 0 var(--pad);}
#sec-03 .leadin .body-lg{color: var(--muted-on-dark); max-width: 640px; margin-top: 14px;}
#sec-03 .ailayer{position: relative; background: var(--bg-dark);}
#sec-03 .ailayer-sticky{position: relative;}
#sec-03 .ailayer-head{max-width: 760px;}
#sec-03 .ailayer-head .h2{margin-top: 16px;}
#sec-03 .ailayer-head .body-lg{color: var(--muted-on-dark); margin-top: 14px; max-width: 600px;}
#sec-03 .deck-wrap{margin-top: 22px;}
#sec-03 .deck-stage{position: relative; width: 100%; max-width: 1140px; margin: 0px auto; min-height: 668px; --shift: 0px;}
#sec-03 .ai-card{background: var(--bg-dark-2); border: 1px solid var(--border-dark); border-radius: var(--r-lg); padding: 24px 26px; display: flex; flex-direction: column; gap: 15px; transition: border-color 220ms var(--ease);}
#sec-03 .deck-card{position: absolute; top: 0px; left: 50%; width: min(1010px, 100%); transform-origin: 50% 50%; transition: transform 560ms var(--spring), opacity 440ms var(--ease), filter 440ms var(--ease), box-shadow 440ms var(--ease); will-change: transform, opacity;}
#sec-03 .deck-card.is-front{transform: translate(calc(-50% + var(--shift)), 0) rotate(0deg) scale(1); opacity: 1; filter: none; z-index: 30; box-shadow: rgba(0, 0, 0, 0.8) 0px 34px 84px -34px;}
#sec-03 .deck-card.is-mid{transform: translate(calc(-50% + var(--shift) + 50px), 30px) rotate(2.6deg) scale(0.965); opacity: 0.62; filter: blur(0.4px); z-index: 20; box-shadow: rgba(0, 0, 0, 0.64) 0px 26px 66px -36px; cursor: pointer;}
#sec-03 .deck-card.is-back{transform: translate(calc(-50% + var(--shift) + 96px), 58px) rotate(5deg) scale(0.93); opacity: 0.4; filter: blur(0.9px); z-index: 10; box-shadow: rgba(0, 0, 0, 0.52) 0px 20px 58px -38px; cursor: pointer;}
#sec-03 .deck-card.is-leaving{z-index: 50;}
#sec-03 .deck-card.is-mid:hover{transform: translate(calc(-50% + var(--shift) + 42px), 19px) rotate(2deg) scale(0.978); opacity: 0.8;}
#sec-03 .deck-card.is-back:hover{transform: translate(calc(-50% + var(--shift) + 86px), 45px) rotate(4.2deg) scale(0.945); opacity: 0.56;}
#sec-03 .deck-card:not(.is-front) .ai-demo, #sec-03 .deck-card:not(.is-front) .demo-caption{pointer-events: none;}
#sec-03 .deck-stage.shuffling .deck-card{pointer-events: none;}
#sec-03 .deck-pager{display: flex; gap: 8px; justify-content: center; align-items: center; margin-top: 26px; flex-wrap: wrap;}
#sec-03 .pager-item{display: inline-flex; align-items: center; gap: 9px; cursor: pointer; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.04em; text-transform: lowercase; color: var(--muted-on-dark); background: none; border: 0px; padding: 6px 12px; border-radius: var(--r-pill); transition: color 200ms var(--ease), background 200ms var(--ease);}
#sec-03 .pager-item:hover{color: var(--text-on-dark);}
#sec-03 .pager-item .pnum{width: 22px; height: 22px; border-radius: 50%; flex: 0 0 auto; display: flex; align-items: center; justify-content: center; font-size: 10px; font-weight: 700; color: var(--muted-on-dark); border: 1.5px solid var(--border-dark-strong); background: var(--bg-dark); transition: color 220ms var(--ease), background 220ms var(--ease), border-color 220ms var(--ease);}
#sec-03 .pager-item.active{color: var(--text-on-dark);}
#sec-03 .pager-item.active .pnum{background: var(--accent-amber); color: rgb(26, 26, 26); border-color: var(--accent-amber);}
#sec-03 .deck-hint{text-align: center; margin-top: 14px; font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.06em; text-transform: lowercase; color: var(--muted-on-dark); opacity: 0; transition: opacity 500ms var(--ease); display: inline-flex; align-items: center; gap: 8px;}
#sec-03 .deck-hint::before{content: "↕"; color: var(--accent-amber);}
#sec-03 .deck-hint-wrap{display: flex; justify-content: center;}
#sec-03 .deck-hint.show{opacity: 0.65;}
@media (min-width: 981px){
#sec-03 .ailayer{height: 320vh;}
#sec-03 .ailayer-sticky{position: sticky; top: 0px; height: 100vh; overflow: hidden; display: flex; flex-direction: column; justify-content: center; padding: 20px 0px;}
#sec-03 .ailayer-head{margin: 0px auto 0px 0px;}
#sec-03 .deck-stage{--shift: -40px;}
}
#sec-03 .ailayer-cta-block{background: var(--bg-dark); padding: 56px 0 var(--section-pad); position: relative;}
#sec-03 .ai-head{display: flex; align-items: flex-start; gap: 13px;}
#sec-03 .ai-ico{width: 38px; height: 38px; border-radius: var(--r-sm); flex: 0 0 auto; border: 1px solid var(--indigo-line); background: var(--indigo-fill); display: flex; align-items: center; justify-content: center; color: var(--accent-indigo-2);}
#sec-03 .ai-ico .ti{font-size: 20px;}
#sec-03 .ai-head .t{font-size: 17px; font-weight: 500; line-height: 1.2;}
#sec-03 .ai-head .d{font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.01em; color: var(--muted-on-dark); margin-top: 6px; line-height: 1.55;}
#sec-03 .ai-demo{height: 430px; background: var(--bg-dark-3); border: 1px solid var(--border-dark); border-radius: var(--r-md); overflow: hidden; position: relative; display: flex; flex-direction: column;}
#sec-03 .ai-demo-head{flex: 0 0 auto; height: 38px; display: flex; align-items: center; justify-content: space-between; padding: 0px 13px; border-bottom: 1px solid var(--border-dark); font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.03em; color: var(--muted-on-dark);}
#sec-03 .pulsedot{display: inline-block; width: 7px; height: 7px; border-radius: 50%; background: var(--pos); position: relative; flex: 0 0 auto;}
#sec-03 .pulsedot::after{content: ""; position: absolute; inset: 0px; border-radius: 50%; background: var(--pos); animation: pulsering 2.4s var(--ease) infinite;}
@keyframes pulsering { 
  0% { transform: scale(1); opacity: 0.5; }
  70% { transform: scale(3); opacity: 0; }
  100% { transform: scale(3); opacity: 0; }
}
#sec-03 .ai-flag{display: inline-flex; align-items: center; gap: 7px; font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.04em; color: var(--accent-indigo-2);}
#sec-03 .ai-flag .dot{width: 6px; height: 6px; border-radius: 50%; background: var(--accent-indigo); position: relative;}
#sec-03 .ai-flag .dot::after{content: ""; position: absolute; inset: 0px; border-radius: 50%; background: var(--accent-indigo); animation: pulsering 2.6s var(--ease) infinite;}
#sec-03 .demo-caption{margin-top: 4px; font-family: var(--font-mono); font-size: 11px; letter-spacing: 0.05em; text-transform: lowercase; color: var(--muted-on-dark); display: inline-flex; align-items: center; gap: 8px;}
#sec-03 .demo-caption::before{content: "↳"; color: var(--accent-amber);}
#sec-03 .caret::after{content: "▏"; color: var(--accent-indigo-2); margin-left: -2px; animation: 1s step-end 0s infinite normal none running blink;}
@keyframes blink { 
  50% { opacity: 0; }
}
#sec-03 .email-split{flex: 1 1 0%; min-height: 0px; display: grid; grid-template-columns: 1fr 1fr;}
#sec-03 .inbox{min-height: 0px; display: flex; flex-direction: column; align-content: flex-start; border-right: 1px solid var(--border-dark); overflow: hidden;}
#sec-03 .email{border-bottom: 1px solid var(--border-dark); cursor: pointer; transition: background 200ms var(--ease);}
#sec-03 .email:hover{background: rgba(124, 108, 255, 0.05);}
#sec-03 .email.active{background: rgba(124, 108, 255, 0.1);}
#sec-03 .email-row{display: flex; align-items: center; gap: 9px; height: 56px; padding: 0px 14px;}
#sec-03 .email .unread{width: 6px; height: 6px; border-radius: 50%; background: var(--accent-indigo); flex: 0 0 auto; opacity: 0; transition: opacity 200ms;}
#sec-03 .email.is-unread .unread{opacity: 1;}
#sec-03 .email .who{font-size: 12.5px; font-weight: 500; flex: 0 0 auto; width: 96px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;}
#sec-03 .email .subj{font-size: 12px; color: var(--muted-on-dark); flex: 1 1 0%; min-width: 0px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;}
#sec-03 .echip{font-family: var(--font-mono); font-size: 9.5px; letter-spacing: 0.01em; flex: 0 0 auto; padding: 3px 8px; border-radius: var(--r-pill); white-space: nowrap; border: 1px solid var(--indigo-line); color: var(--accent-indigo-2); background: var(--indigo-fill);}
#sec-03 .echip.sorting{color: var(--muted-on-dark); border-color: var(--border-dark-strong); background: transparent;}
#sec-03 .email-panel{position: relative; min-width: 0px; padding: 16px 18px; display: flex; flex-direction: column; gap: 11px;}
#sec-03 .email-panel-empty{position: absolute; inset: 0px; display: flex; align-items: center; justify-content: center; text-align: center; padding: 0px 28px; font-family: var(--font-mono); font-size: 10.5px; line-height: 1.6; letter-spacing: 0.03em; color: var(--muted-on-dark);}
#sec-03 .ep-from{display: flex; align-items: center; gap: 10px; justify-content: space-between;}
#sec-03 .ep-who{font-size: 13.5px; font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;}
#sec-03 .ep-subj{font-size: 12px; color: var(--muted-on-dark); line-height: 1.45;}
#sec-03 .email-summary{display: flex; gap: 8px; align-items: flex-start; font-size: 11.5px; line-height: 1.5; color: var(--muted-on-dark); padding: 9px 0px 10px; border-top: 1px solid var(--border-dark); border-bottom: 1px solid var(--border-dark);}
#sec-03 .email-summary .ti{color: var(--accent-indigo-2); font-size: 13px; margin-top: 1px; flex: 0 0 auto;}
#sec-03 .email-draft{border: 1px solid var(--border-dark); border-radius: var(--r-sm); background: rgba(0, 0, 0, 0.18); padding: 10px 11px; font-size: 11.5px; line-height: 1.55; color: var(--text-on-dark); flex: 1 1 0%; min-height: 0px; overflow: hidden;}
#sec-03 .email-draft .lbl{font-family: var(--font-mono); font-size: 9px; letter-spacing: 0.08em; color: var(--muted-on-dark); display: block; margin-bottom: 6px;}
#sec-03 .draft-actions{display: flex; gap: 8px;}
#sec-03 .mini-btn{font-family: var(--font-sans); font-size: 11px; font-weight: 500; cursor: pointer; padding: 7px 14px; border-radius: var(--r-pill); border: 1px solid transparent; line-height: 1; display: inline-flex; align-items: center; gap: 6px; transition: transform 180ms var(--ease), border-color 180ms var(--ease), background 180ms var(--ease);}
#sec-03 .mini-btn--send{background: var(--accent-indigo); color: rgb(255, 255, 255);}
#sec-03 .mini-btn--send:hover{transform: translateY(-1px); background: var(--accent-indigo-2);}
#sec-03 .mini-btn--ghost{background: transparent; color: var(--muted-on-dark); border-color: var(--border-dark-strong);}
#sec-03 .mini-btn--ghost:hover{color: var(--text-on-dark); border-color: var(--text-on-dark);}
@keyframes emailIn { 
  0% { max-height: 0px; opacity: 0; }
  100% { max-height: 56px; opacity: 1; }
}
#sec-03 .email.slidein{animation: emailIn 420ms var(--ease);}
#sec-03 .chat-split{flex: 1 1 0%; min-height: 0px; display: grid; grid-template-columns: 172px 1fr;}
#sec-03 .chat-aside{border-right: 1px solid var(--border-dark); padding: 20px 18px; display: flex; flex-direction: column; gap: 11px;}
#sec-03 .chat-avatar{width: 42px; height: 42px; border-radius: 50%; flex: 0 0 auto; background: var(--indigo-fill); border: 1px solid var(--indigo-line); color: var(--accent-indigo-2); display: flex; align-items: center; justify-content: center;}
#sec-03 .chat-avatar .ti{font-size: 21px;}
#sec-03 .chat-id{font-size: 14px; font-weight: 500; line-height: 1.25; margin-top: 2px;}
#sec-03 .chat-status{display: inline-flex; align-items: center; gap: 7px; font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.04em; color: var(--pos);}
#sec-03 .chat-aside-note{font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.02em; line-height: 1.5; color: var(--muted-on-dark); margin-top: auto;}
#sec-03 .chat{min-width: 0px; display: flex; flex-direction: column;}
#sec-03 .chat-log{flex: 1 1 0%; min-height: 0px; padding: 18px 22px; display: flex; flex-direction: column; justify-content: flex-end; gap: 9px; overflow: hidden;}
#sec-03 .bubble{max-width: 78%; padding: 9px 13px; border-radius: 13px; font-size: 12.5px; line-height: 1.5; animation: bubbleIn 300ms var(--spring);}
@keyframes bubbleIn { 
  0% { opacity: 0; transform: translateY(6px); }
  100% { opacity: 1; transform: none; }
}
#sec-03 .bubble.bot{align-self: flex-start; background: var(--bg-dark-2); border: 1px solid var(--border-dark); border-bottom-left-radius: 4px; color: var(--text-on-dark);}
#sec-03 .bubble.user{align-self: flex-end; background: var(--accent-indigo); color: rgb(255, 255, 255); border-bottom-right-radius: 4px;}
