/* =================================================================
   Hero scrubber — scroll-linked video frame seeking.
   - section is 200vh; runway = section.offsetHeight - viewport.
   - progress 0..1 drives video.currentTime = progress * duration
   - end-frame poster crossfades in at progress >= 0.99
   - headline fades out by progress 0.2
   - body gets `hero-scrolled` class once progress > 0.05 (header bg)
   - Disabled on mobile (<=900px) — static poster shown instead.
   ================================================================= */
(function() {
  const section   = document.querySelector('.hero-scrub');
  const video     = document.getElementById('hero-video');
  const headline  = document.querySelector('.hero-headline');
  const scrollCue = document.getElementById('scroll-cue');

  if (!section || !video) return;

  /* Trim the scrub: stop before the dashboard reveals at the very end.
     The source video ends on a fully-revealed dashboard; we cap the
     scrub at ~82% so the user sees the dive-in but not the dashboard. */
  const SCRUB_END_RATIO = 0.82;

  let ticking = false;
  let videoReady = false;
  let lastSeekTime = -1;

  function isDesktop() { return window.innerWidth > 900; }

  function seekTo(t) {
    if (!videoReady) return;
    if (Math.abs(t - lastSeekTime) < 0.016) return; // ~1 frame
    try {
      video.currentTime = t;
      lastSeekTime = t;
    } catch (e) { /* non-fatal */ }
  }

  var heroVisible=true;
  function update() {
    if (document.hidden || !heroVisible) { ticking=false; return; }
    if (!isDesktop()) {
      document.body.classList.remove('hero-scrolled');
      if (headline) { headline.style.opacity = ''; headline.style.transform = ''; }
      if (scrollCue) scrollCue.style.opacity = '';
      ticking = false;
      return;
    }

    const rect = section.getBoundingClientRect();
    const sectionTop = window.scrollY + rect.top;
    const runway = section.offsetHeight - window.innerHeight;
    const raw = (window.scrollY - sectionTop) / Math.max(1, runway);
    const progress = Math.max(0, Math.min(1, raw));

    // Seek video — trimmed so we never reach the dashboard reveal
    if (videoReady && video.duration && !isNaN(video.duration)) {
      const targetTime = progress * video.duration * SCRUB_END_RATIO;
      seekTo(targetTime);
    }

    // Headline fade — gone by 20% scroll
    if (headline) {
      const fade = Math.max(0, 1 - progress / 0.2);
      headline.style.opacity = fade.toFixed(3);
      headline.style.transform = `translateY(${((1 - fade) * -20).toFixed(2)}px)`;
    }

    // Video fade-to-dark in the final 12% of scroll progress.
    // .hero-scrub's background reads as continuous dark surface beneath.
    const videoFade = progress < 0.88 ? 1 : Math.max(0, 1 - (progress - 0.88) / 0.12);
    video.style.opacity = videoFade.toFixed(3);

    // Scroll cue fades out quickly
    if (scrollCue) {
      const cueFade = Math.max(0, 1 - progress / 0.08);
      scrollCue.style.opacity = cueFade.toFixed(3);
    }

    // Frosted header once you've started scrolling
    document.body.classList.toggle('hero-scrolled', progress > 0.05);

    ticking = false;
  }

  function onScroll() {
    if (!ticking) {
      ticking = true;
      requestAnimationFrame(update);
    }
  }

  function markReady() {
    if (videoReady) return;
    if (!video.duration || isNaN(video.duration)) return;
    videoReady = true;
    // Force a paint of the first frame so the poster swaps to live video
    try { video.currentTime = 0.001; } catch (e) {}
    update();
  }

  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', onScroll, { passive: true });
  document.addEventListener('visibilitychange', onScroll);
  if('IntersectionObserver' in window){ new IntersectionObserver(function(es){es.forEach(function(e){heroVisible=e.isIntersecting;});onScroll();},{threshold:0}).observe(section); }

  // Multiple readiness signals — different browsers fire different ones first.
  video.addEventListener('loadedmetadata', markReady);
  video.addEventListener('loadeddata',     markReady);
  video.addEventListener('canplay',        markReady);
  video.addEventListener('canplaythrough', markReady);

  // Fetch the MP4 fully into memory and feed it via a blob URL so the
  // whole stream is seekable. Required when the host doesn't support
  // HTTP byte-range requests (which otherwise pins seekable to [0,0]).
  (async function loadVideoAsBlob() {
    const src = video.dataset.src;
    if (!src) return;
    try {
      const res = await fetch(src);
      if (!res.ok) throw new Error('fetch failed: ' + res.status);
      const blob = await res.blob();
      video.src = URL.createObjectURL(blob);
      try { video.load(); } catch (e) {}
    } catch (err) {
      // Fall back to direct src — at least the poster will show.
      console.warn('[hero-scrub] blob load failed, falling back to direct src:', err);
      video.src = src;
      try { video.load(); } catch (e) {}
    }
  })();

  if (video.readyState >= 1) markReady();

  // Initial paint (overlay state) even before video is ready
  update();
})();


