/* =================================================================
   SHARED HELPERS
   ================================================================= */
const RM = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

function inrNum(v) {
  v = Math.round(v);
  const s = String(v);
  if (s.length <= 3) return s;
  const last3 = s.slice(-3);
  let rest = s.slice(0, -3);
  rest = rest.replace(/\B(?=(\d{2})+(?!\d))/g, ',');
  return rest + ',' + last3;
}
function inr(v) { return '₹' + inrNum(v); }

/* count-up with cancel-token so re-triggers don't fight */
function countUp(el, to, fmt, dur) {
  fmt = fmt || (v => String(Math.round(v)));
  const token = (el._cu || 0) + 1; el._cu = token;
  if (RM) { el.textContent = fmt(to); return; }
  dur = dur || 650;
  const start = performance.now();
  (function tick(now) {
    if (el._cu !== token) return;
    const t = Math.min(1, (now - start) / dur);
    const e = 1 - Math.pow(1 - t, 3);
    el.textContent = fmt(to * e);
    if (t < 1) requestAnimationFrame(tick);
  })(performance.now());
}


/* =================================================================
   SHOWCASE — scroll driver, entry transition, rail fill + nav,
   and two-tier (off / live / focused) demo-mode dispatch.
   ================================================================= */
(function () {
  const section   = document.getElementById('showcase');
  const demos     = Array.from(section.querySelectorAll('.stage-demo'));
  const railItems = Array.from(section.querySelectorAll('.rail-item'));
  const railList  = document.getElementById('rail-list');
  const railFill  = document.getElementById('rail-fill');
  const N = demos.length;
  let activeIndex = -1;
  let ticking = false;

  function isDesktop() { return window.innerWidth > 900; }

  /* ---- two-tier activity dispatch: 'off' | 'live' (slow) | 'focused' (full+count-ups) ---- */
  const demoMode = new Array(N).fill('off');
  function setDemoMode(i, mode) {
    if (demoMode[i] === mode) return;
    demoMode[i] = mode;
    demos[i].dispatchEvent(new CustomEvent('demo-mode', { detail: mode }));
  }

  let sectionLive  = false;             // showcase in viewport (desktop)
  let tabVisible   = !document.hidden;  // tab foregrounded
  let focusedIndex = -1;                // desktop scroll-zone demo
  const nearMobile   = new Array(N).fill(false);  // near viewport (mobile → live)
  const centerMobile = new Array(N).fill(false);  // centered (mobile → focused)

  function applyModes() {
    if (RM) { return; }  /* reduced-motion: never run ambient loops */
    if (isDesktop()) {
      const liveOK = sectionLive && tabVisible;
      demos.forEach((d, idx) => setDemoMode(idx, !liveOK ? 'off' : (idx === focusedIndex ? 'focused' : 'live')));
    } else {
      demos.forEach((d, idx) => {
        let mode = 'off';
        if (tabVisible && nearMobile[idx]) mode = centerMobile[idx] ? 'focused' : 'live';
        setDemoMode(idx, mode);
      });
    }
  }

  function setActive(i) {
    if (i === activeIndex) return;
    activeIndex = i;
    demos.forEach((d, idx) => d.classList.toggle('active', idx === i));
    railItems.forEach((r, idx) => r.classList.toggle('active', idx === i));
    if (isDesktop()) { focusedIndex = i; applyModes(); }
  }

  function update() {
    ticking = false;
    if (!isDesktop()) return;
    const rect = section.getBoundingClientRect();
    const sectionTop = window.scrollY + rect.top;
    const runway = section.offsetHeight - window.innerHeight;
    const raw = (window.scrollY - sectionTop) / Math.max(1, runway);
    const progress = Math.max(0, Math.min(1, raw));
    setActive(Math.max(0, Math.min(N - 1, Math.floor(progress * N))));
    const track = railList.clientHeight - 32;
    railFill.style.height = Math.max(0, progress * track) + 'px';
  }

  function onScroll() { if (!ticking) { ticking = true; requestAnimationFrame(update); } }
  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', () => { onScroll(); applyModes(); }, { passive: true });

  /* entry transition */
  if ('IntersectionObserver' in window) {
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) { section.classList.add('showcase-entered'); io.disconnect(); } });
    }, { threshold: 0.2 });
    io.observe(section);
  } else { section.classList.add('showcase-entered'); }

  /* desktop: whole section breathes once it enters the viewport (all four go 'live'),
     stops entirely when the section leaves */
  if ('IntersectionObserver' in window) {
    const liveIO = new IntersectionObserver((entries) => {
      entries.forEach(e => { sectionLive = e.isIntersecting; });
      applyModes();
    }, { threshold: 0.1 });
    liveIO.observe(section);

    /* mobile: 'near viewport' → live (slow), 'centered' → focused (full + count-ups) */
    const nearIO = new IntersectionObserver((entries) => {
      entries.forEach(e => { nearMobile[+e.target.dataset.index] = e.isIntersecting; });
      if (!isDesktop()) applyModes();
    }, { rootMargin: '180px 0px 180px 0px', threshold: 0 });
    const centerIO = new IntersectionObserver((entries) => {
      entries.forEach(e => { centerMobile[+e.target.dataset.index] = e.isIntersecting; });
      if (!isDesktop()) applyModes();
    }, { rootMargin: '-38% 0px -38% 0px', threshold: 0 });
    demos.forEach(d => { nearIO.observe(d); centerIO.observe(d); });
  }

  /* pause every loop when the tab is backgrounded */
  document.addEventListener('visibilitychange', () => { tabVisible = !document.hidden; applyModes(); });

  /* rail click = jump to that demo's runway segment */
  railItems.forEach(item => {
    item.addEventListener('click', () => {
      if (!isDesktop()) return;
      const i = +item.dataset.index;
      const rect = section.getBoundingClientRect();
      const sectionTop = window.scrollY + rect.top;
      const runway = section.offsetHeight - window.innerHeight;
      window.scrollTo({ top: sectionTop + ((i + 0.5) / N) * runway, behavior: 'smooth' });
    });
  });

  update();
  /* initial activation AFTER demo modules have attached listeners */
  requestAnimationFrame(() => { if (isDesktop()) setActive(0); applyModes(); });
})();


