   DEMO 2 — school: roster, count-up, sync loop, flip + save ripple
   ================================================================= */
(function () {
  const demoEl = document.querySelector('.stage-demo[data-index="1"]');
  const grid = document.getElementById('school-grid');
  const countEl = document.getElementById('sc-present');
  const barEl = document.getElementById('sc-bar');
  const saveBtn = document.getElementById('school-save');
  const ripple = document.getElementById('save-ripple');
  const hint = document.getElementById('school-hint');
  const syncEl = document.getElementById('school-sync');
  if (!grid) return;

  const roster = [
    { nm:'Aarav Sharma', roll:'01', t:0, p:true }, { nm:'Diya Menon', roll:'02', t:1, p:true },
    { nm:'Kabir Rao', roll:'03', t:2, p:false }, { nm:'Ananya Pillai', roll:'04', t:3, p:true },
    { nm:'Vihaan Kapoor', roll:'05', t:4, p:true }, { nm:'Ishika Nair', roll:'06', t:0, p:true },
    { nm:'Reyansh Gupta', roll:'07', t:1, p:false }, { nm:'Saanvi Iyer', roll:'08', t:2, p:true },
    { nm:'Arjun Bose', roll:'09', t:3, p:true }, { nm:'Myra Joshi', roll:'10', t:4, p:false },
    { nm:'Vivaan Das', roll:'11', t:0, p:true }, { nm:'Aadhya Reddy', roll:'12', t:1, p:true }
  ];
  const tints = [
    ['rgba(124,108,255,0.18)', '#b3a8ff'],
    ['rgba(78,201,138,0.16)',  '#7fe0ab'],
    ['rgba(96,165,250,0.16)',  '#9cc6ff'],
    ['rgba(192,132,252,0.16)', '#d6b4fc'],
    ['rgba(45,212,191,0.14)',  '#7fe6db']
  ];
  const total = roster.length;
  function initials(n) { return n.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase(); }

  roster.forEach((s, i) => {
    const c = document.createElement('div');
    c.className = 'stu ' + (s.p ? 'present' : 'absent');
    c.dataset.i = i;
    c.innerHTML =
      '<span class="badge"><i class="ti ' + (s.p ? 'ti-check' : 'ti-minus') + '"></i></span>' +
      '<div class="av" style="background:' + tints[s.t][0] + ';color:' + tints[s.t][1] + ';">' + initials(s.nm) + '</div>' +
      '<div class="nm">' + s.nm.split(' ')[0] + '</div>' +
      '<div class="roll">roll ' + s.roll + '</div>';
    grid.appendChild(c);
  });

  /* coaching cue: invite the first tap on a student card */
  let schoolCue = true;
  if (!RM) {
    const cueCard = grid.querySelector('.stu[data-i="2"]');
    if (cueCard) {
      cueCard.classList.add('coach');
      const tip = document.createElement('span');
      tip.className = 'coach-tip'; tip.textContent = 'tap to mark present';
      cueCard.appendChild(tip);
    }
  }

  function presentCount() { return grid.querySelectorAll('.stu.present').length; }
  function refresh(animate) {
    const p = presentCount();
    if (animate) countUp(countEl, p, v => String(Math.round(v)), 600);
    else countEl.textContent = p;
    barEl.style.width = (p / total * 100) + '%';
  }

  grid.addEventListener('click', (e) => {
    const card = e.target.closest('.stu');
    if (!card) return;
    if (schoolCue) {
      schoolCue = false;
      const c = grid.querySelector('.stu.coach');
      if (c) { const t = c.querySelector('.coach-tip'); if (t) t.remove(); c.classList.remove('coach'); }
    }
    const present = card.classList.contains('present');
    card.classList.toggle('present', !present);
    card.classList.toggle('absent', present);
    card.querySelector('.badge i').className = 'ti ' + (present ? 'ti-minus' : 'ti-check');
    if (!RM) { card.classList.remove('flip'); void card.offsetWidth; card.classList.add('flip'); }
    refresh(false);
    if (saveBtn.classList.contains('saved')) {
      saveBtn.classList.remove('saved');
      saveBtn.innerHTML = '<span class="ripple" id="save-ripple"></span><i class="ti ti-device-floppy"></i> Save attendance';
      hint.classList.remove('ok'); hint.textContent = 'tap a student to toggle';
    }
  });

  let saveTimer;
  saveBtn.addEventListener('click', (e) => {
    const r = saveBtn.querySelector('.ripple');
    if (r && !RM) { const rect = saveBtn.getBoundingClientRect(); r.style.left = (e.clientX - rect.left) + 'px'; r.style.top = (e.clientY - rect.top) + 'px'; }
    saveBtn.classList.add('saved');
    saveBtn.innerHTML = '<span class="ripple"></span><i class="ti ti-check"></i> Saved';
    const p = presentCount();
    hint.classList.add('ok');
    hint.innerHTML = '<i class="ti ti-check"></i> synced to ' + p + ' parents via SMS ✓';
    clearTimeout(saveTimer);
    saveTimer = setTimeout(() => {
      saveBtn.classList.remove('saved');
      saveBtn.innerHTML = '<span class="ripple"></span><i class="ti ti-device-floppy"></i> Save attendance';
      hint.classList.remove('ok'); hint.textContent = 'tap a student to toggle';
    }, 2600);
  });

  /* ambient: "synced Ns ago" timestamp ticks — fast when focused, slow when live */
  let counted = false, syncTimer = null, secs = 0;
  function startSync(interval) {
    if (RM) return;
    clearInterval(syncTimer);
    const step = Math.round(interval / 1000);
    secs = 0; syncEl.textContent = 'synced just now';
    syncTimer = setInterval(() => {
      secs += step;
      if (secs > 12) { secs = 0; syncEl.textContent = 'synced just now'; }
      else syncEl.textContent = 'synced ' + secs + 's ago';
    }, interval);
  }
  function stopSync() { clearInterval(syncTimer); syncTimer = null; }

  demoEl.addEventListener('demo-mode', (e) => {
    const m = e.detail;
    if (m === 'off') { stopSync(); return; }
    if (m === 'focused') { if (!counted) { refresh(true); counted = true; } startSync(3000); }
    else { startSync(8000); }       /* live = slow tick */
  });
  refresh(false);
  if (RM) refresh(true);            /* reduced-motion: show final values immediately */
})();


/* =================================================================
   DEMO 3 — restaurant: stats count-up, table meta, ambient flips,
   booking popover + reserve toast
   ================================================================= */
(function () {
  const demoEl = document.querySelector('.stage-demo[data-index="2"]');
  const floor = document.getElementById('floor');
  const pop = document.getElementById('floor-pop');
  const bookedEl = document.getElementById('floor-booked');
  const liveEl = document.getElementById('floor-live');
  const toast = document.getElementById('floor-toast');
  if (!floor) return;

  const tables = [
    { id:'T1', x:16, y:20, s:46, shape:'round', st:'open',     seats:2 },
    { id:'T2', x:38, y:18, s:54, shape:'square', st:'occupied', seats:4, mins:80 },
    { id:'T3', x:62, y:20, s:46, shape:'round', st:'open',     seats:2 },
    { id:'T4', x:84, y:22, s:54, shape:'square', st:'reserved', seats:4 },
    { id:'T5', x:18, y:50, s:54, shape:'square', st:'occupied', seats:4, mins:35 },
    { id:'T6', x:40, y:52, s:46, shape:'round', st:'open',     seats:2 },
    { id:'T7', x:63, y:52, s:62, shape:'square', st:'occupied', seats:6, mins:52 },
    { id:'T8', x:85, y:54, s:46, shape:'round', st:'open',     seats:2 },
    { id:'T9', x:26, y:82, s:62, shape:'square', st:'reserved', seats:6 },
    { id:'T10', x:60, y:82, s:64, shape:'round', st:'open',     seats:6 },
    { id:'BAR', x:86, y:84, s:50, shape:'square', st:'occupied', seats:3, mins:18 }
  ];
  const TOTAL = 20;
  let activeTable = null;
  /* interaction-safety state for ambient flips */
  let popOpen = false, hoveredId = null, firstBookingDone = false, cuedId = null;
  const lastInteract = {};                       /* id -> timestamp */
  function touch(id) { if (id) lastInteract[id] = performance.now(); }

  function bookedCount() { return tables.filter(t => t.st !== 'open').length; }
  function metaText(t) { const h = Math.floor(t.mins / 60), m = t.mins % 60; return t.seats + ' · ' + (h ? h + 'h' : '') + m + 'm'; }

  function subLabel(t) {
    if (t.st === 'occupied') return '<span class="tmeta">' + metaText(t) + '</span>';
    if (t.st === 'open')     return '<span class="tmeta tmeta-open">+ book</span>';
    return '';
  }

  /* draw chairs around each table so the floor reads as TABLES, not coloured dots */
  function addChairs(t) {
    const n = Math.min(t.seats || 2, 8);
    for (let i = 0; i < n; i++) {
      const a = (i / n) * Math.PI * 2 - Math.PI / 2;
      const ch = document.createElement('span');
      ch.className = 'chair';
      ch.style.left = (50 + Math.cos(a) * 64) + '%';
      ch.style.top  = (50 + Math.sin(a) * 64) + '%';
      t.el.appendChild(ch);
    }
  }

  tables.forEach(t => {
    const el = document.createElement('div');
    el.className = 'table ' + (t.shape === 'round' ? 'round' : '');
    el.style.left = t.x + '%'; el.style.top = t.y + '%';
    el.style.width = t.s + 'px'; el.style.height = t.s + 'px';
    el.dataset.state = t.st; el.dataset.id = t.id;
    el.innerHTML = '<span class="tnum">' + t.id + '</span>' + subLabel(t);
    floor.appendChild(el); t.el = el;
    addChairs(t);
  });

  function setState(t, st) {
    t.st = st; t.el.dataset.state = st;
    const meta = t.el.querySelector('.tmeta');
    if (meta) meta.remove();
    if (st === 'occupied') { t.mins = t.mins || 5; t.el.insertAdjacentHTML('beforeend', '<span class="tmeta">' + metaText(t) + '</span>'); }
    else if (st === 'open') { t.el.insertAdjacentHTML('beforeend', '<span class="tmeta tmeta-open">+ book</span>'); }
  }

  /* coaching cue: pulsing ring + floating label on ONE open table, until first booking */
  function setupCue() {
    const cued = tables.find(t => t.id === 'T6' && t.st === 'open') || tables.find(t => t.st === 'open');
    if (!cued) return;
    cuedId = cued.id;
    cued.el.classList.add('cue');
    const lbl = document.createElement('span');
    lbl.className = 'cue-label'; lbl.textContent = 'tap to book →';
    cued.el.appendChild(lbl);
  }
  function clearCue() {
    if (!cuedId) return;
    const t = tables.find(x => x.id === cuedId);
    if (t) {
      t.el.classList.remove('cue');
      const l = t.el.querySelector('.cue-label');
      if (l) { l.classList.add('out'); setTimeout(() => l.remove(), 400); }
    }
    cuedId = null;
  }
  setupCue();

  /* track the hovered table so ambient never flips it (desktop) */
  floor.addEventListener('mouseover', (e) => { const el = e.target.closest('.table'); if (el) { hoveredId = el.dataset.id; touch(hoveredId); } });
  floor.addEventListener('mouseout',  (e) => { const el = e.target.closest('.table'); if (el && el.dataset.id === hoveredId) hoveredId = null; });

  /* stats */
  const stCovers = document.getElementById('st-covers');
  const stTurn = document.getElementById('st-turn');
  const stWait = document.getElementById('st-wait');
  function renderBooked(animate) {
    if (animate) countUp(bookedEl, bookedCount(), v => String(Math.round(v)), 500);
    else bookedEl.textContent = bookedCount();
  }

  /* popover */
  const popTable = document.getElementById('pop-table');
  const popName = document.getElementById('pop-name');
  const popSize = document.getElementById('pop-size');
  const popTimes = document.getElementById('pop-times');

  function positionPop(tableEl, popEl) {
    popEl = popEl || pop;
    const fr = floor.getBoundingClientRect(), tr = tableEl.getBoundingClientRect();
    const pr = popEl.getBoundingClientRect();
    const popW = pr.width || 210, popH = pr.height || 290;
    let left = (tr.left - fr.left) + tr.width + 12, top = (tr.top - fr.top);
    if (left + popW > fr.width) left = (tr.left - fr.left) - popW - 12;
    if (left < 4) left = 4;
    if (top + popH > fr.height) top = Math.max(4, fr.height - popH - 4);
    popEl.style.left = left + 'px'; popEl.style.top = top + 'px';
  }

  floor.addEventListener('click', (e) => {
    const el = e.target.closest('.table'); if (!el) return;
    const t = tables.find(x => x.id === el.dataset.id); if (!t) return;
    if (el.dataset.state === 'open') {
      orderPop.classList.remove('open');
      activeTable = t; touch(t.id); popOpen = true;
      popTable.textContent = el.dataset.id;
      popName.value = 'Walk-in'; popSize.textContent = '2';
      pop.classList.add('open'); positionPop(el, pop);
    } else if (el.dataset.state === 'occupied') {
      pop.classList.remove('open');
      openOrder(t, el);
    }
  });
  function closePop() { pop.classList.remove('open'); popOpen = false; if (activeTable) touch(activeTable.id); }
  document.getElementById('pop-close').addEventListener('click', closePop);
  document.getElementById('pop-minus').addEventListener('click', () => { popSize.textContent = Math.max(1, (+popSize.textContent) - 1); });
  document.getElementById('pop-plus').addEventListener('click', () => { popSize.textContent = Math.min(12, (+popSize.textContent) + 1); });
  popTimes.addEventListener('click', (e) => {
    const t = e.target.closest('.ptime'); if (!t) return;
    popTimes.querySelectorAll('.ptime').forEach(x => x.classList.remove('sel'));
    t.classList.add('sel');
  });

  let toastTimer;
  function showToast(msg) {
    toast.querySelector('span').textContent = msg;
    toast.classList.add('show');
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => toast.classList.remove('show'), 2600);
  }

  document.getElementById('pop-reserve').addEventListener('click', () => {
    if (!activeTable) return;
    touch(activeTable.id);
    setState(activeTable, 'reserved');
    const nm = (popName.value || 'Walk-in').trim();
    const size = popSize.textContent;
    const time = (popTimes.querySelector('.ptime.sel') || {}).textContent || '7:30';
    const label = document.createElement('span');
    label.className = 'tname'; label.textContent = nm.toLowerCase().slice(0, 12);
    activeTable.el.appendChild(label);
    requestAnimationFrame(() => requestAnimationFrame(() => label.classList.add('in')));
    renderBooked(true);
    showToast(activeTable.id + ' reserved · ' + time + ' · party of ' + size + ' ✓');
    pop.classList.remove('open'); popOpen = false;
    if (!firstBookingDone) { firstBookingDone = true; clearCue(); }   /* fade the coaching cue */
    activeTable = null;
  });

  /* ----- take-order service (occupied tables) ----- */
  const orderPop = document.getElementById('floor-order');
  const orderTableEl = document.getElementById('order-table');
  const orderMenuEl = document.getElementById('order-menu');
  const orderTotalEl = document.getElementById('order-total');
  const MENU = [
    { nm: 'Margherita', pr: 320 },
    { nm: 'Penne arrabbiata', pr: 280 },
    { nm: 'Garden salad', pr: 190 },
    { nm: 'Tiramisu', pr: 240 },
    { nm: 'Sparkling water', pr: 90 }
  ];
  let orderQty = {}, orderTable = null;
  function renderMenu() {
    orderMenuEl.innerHTML = MENU.map((m, i) =>
      '<div class="omenu-row"><span class="on">' + m.nm + '</span><span class="op">' + inr(m.pr) +
      '</span><span class="oqty" data-i="' + i + '">' + (orderQty[i] || 0) + '</span>' +
      '<button class="oadd" data-i="' + i + '">+</button></div>').join('');
    orderTotalEl.textContent = inr(MENU.reduce((s, m, i) => s + (orderQty[i] || 0) * m.pr, 0));
  }
  function openOrder(t, el) {
    orderTable = t; orderQty = {}; orderTableEl.textContent = t.id;
    renderMenu(); touch(t.id); popOpen = true;
    orderPop.classList.add('open'); positionPop(el, orderPop);
  }
  orderMenuEl.addEventListener('click', (e) => {
    const b = e.target.closest('.oadd'); if (!b) return;
    const i = +b.dataset.i; orderQty[i] = (orderQty[i] || 0) + 1; renderMenu();
  });
  document.getElementById('order-close').addEventListener('click', () => { orderPop.classList.remove('open'); popOpen = false; if (orderTable) touch(orderTable.id); });
  document.getElementById('order-send').addEventListener('click', () => {
    const items = MENU.reduce((s, m, i) => s + (orderQty[i] || 0), 0);
    if (orderTable) touch(orderTable.id);
    orderPop.classList.remove('open'); popOpen = false;
    if (items > 0) showToast('order sent to ' + (orderTable ? orderTable.id : '') + ' · ' + items + ' item' + (items > 1 ? 's' : '') + ' → kitchen ✓');
    orderTable = null;
  });

  /* count-ups (run once, on first focus) */
  let counted = false;
  function runCountUps() {
    countUp(stCovers, 32, v => String(Math.round(v)), 700);
    countUp(stTurn, 48, v => Math.round(v) + 'm', 700);
    countUp(stWait, 3, v => String(Math.round(v)), 700);
    renderBooked(true);
  }

  /* ambient: a peripheral table turns over — never touches the cued / hovered /
     open-popover / recently-used table, and fully pauses while the popover is open */
  let ambTimer = null;
  function startAmbient(interval) {
    if (RM) return;
    clearInterval(ambTimer);
    ambTimer = setInterval(() => {
      if (popOpen) return;                       /* never fight an open booking */
      const now = performance.now();
      const pool = tables.filter(t => {
        if (t.st === 'reserved') return false;
        if (t.id === cuedId) return false;
        if (t.id === hoveredId) return false;
        if (activeTable && t.id === activeTable.id) return false;
        if (lastInteract[t.id] && now - lastInteract[t.id] < 15000) return false;
        return true;
      });
      if (!pool.length) return;
      const t = pool[Math.floor(Math.random() * pool.length)];
      if (t.st === 'occupied') setState(t, 'open');
      else { t.mins = 5; setState(t, 'occupied'); }
      renderBooked(false);
      liveEl.textContent = 'updated just now';
    }, interval);
  }
  function stopAmbient() { clearInterval(ambTimer); ambTimer = null; }

  demoEl.addEventListener('demo-mode', (e) => {
    const m = e.detail;
    if (m === 'off') { stopAmbient(); return; }
    if (m === 'focused') { if (!counted) { runCountUps(); counted = true; } startAmbient(6500); }
    else { startAmbient(12000); }   /* live = slow tick */
  });
  renderBooked(false);
  if (RM) runCountUps();            /* reduced-motion: show final values immediately */
})();


/* =================================================================
   DEMO 4 — e-commerce: tonal cards, fly-to-cart, bought toast, ship bar
   ================================================================= */
(function () {
  const demoEl = document.querySelector('.stage-demo[data-index="3"]');
  const grid = document.getElementById('shop-grid');
  const badge = document.getElementById('cart-badge');
  const cartBtn = document.getElementById('cart-btn');
  const cart = document.getElementById('shop-cart');
  const itemsEl = document.getElementById('cart-items');
  const emptyEl = document.getElementById('cart-empty');
  const totalEl = document.getElementById('cart-total');
  const shipMsg = document.getElementById('ship-msg');
  const shipFill = document.getElementById('ship-fill');
  const toast = document.getElementById('shop-toast');
  if (!grid) return;

  const FREE_SHIP = 2000;
  const IMG = (id, w) => 'https://images.pexels.com/photos/' + id + '/pexels-photo-' + id + '.jpeg?auto=compress&cs=tinysrgb&w=' + (w || 600);
  const SIZES = ['XS', 'S', 'M', 'L', 'XL'];
  const products = [
    { id:1, nm:'Chambray shirt',       pr:2450, rate:'4.8', img:'4831687', desc:'Soft washed cotton-chambray with a relaxed collar — it only gets better with every wear.' },
    { id:2, nm:'Camel wool coat',      pr:6900, rate:'4.9', img:'5868722', stock:2, desc:'A long-line, unstructured coat in a warm camel wool blend. The piece the whole capsule leans on.' },
    { id:3, nm:'Oversized hoodie',     pr:2890, rate:'4.7', img:'6311392', desc:'Heavyweight loop-back cotton with a roomy, drop-shoulder cut and a brushed inner face.' },
    { id:4, nm:'Denim trucker jacket', pr:3600, rate:'4.8', img:'8805458', stock:3, desc:'Rigid indigo denim that breaks in to fit only you. The classic four-pocket trucker.' },
    { id:5, nm:'Linen overshirt',      pr:2750, rate:'4.6', img:'3779662', desc:'A breathable pure-linen overshirt — wear it open as a layer or buttoned on warm evenings.' },
    { id:6, nm:'Essential cotton tee', pr:1290, rate:'4.7', img:'7432216', desc:'The everyday tee in dense combed cotton with a clean-finished neckline. Holds its shape, wash after wash.' }
  ];
  const counts = {};
  const sizeSel = {};
  const stockNow = {}; products.forEach(p => { if (p.stock) stockNow[p.id] = p.stock; });

  function renderGrid() {
    grid.innerHTML = '';
    products.forEach(p => {
      const el = document.createElement('div');
      el.className = 'prod'; el.dataset.id = p.id;
      const stock = stockNow[p.id];
      el.innerHTML =
        '<div class="img">' + (stock ? '<span class="stock" data-id="' + p.id + '">' + stock + ' left</span>' : '') + '<img src="' + IMG(p.img, 500) + '" alt="' + p.nm + '" loading="lazy" /></div>' +
        '<div class="nm">' + p.nm + '</div>' +
        '<div class="meta"><span class="pr">' + inr(p.pr) + '</span><span class="rate">★ ' + p.rate + '</span></div>' +
        '<button class="add-btn" data-id="' + p.id + '"><i class="ti ti-eye"></i> View</button>';
      grid.appendChild(el);
    });
  }
  renderGrid();

  /* coaching cue: invite the first product tap, until the first detail opens */
  let shopCue = true;
  function setShopCue() {
    if (RM || !shopCue) return;
    const first = grid.querySelector('.prod');
    if (!first) return;
    first.classList.add('coach');
    const tip = document.createElement('span');
    tip.className = 'coach-tip'; tip.textContent = 'tap to view →';
    first.appendChild(tip);
  }
  function clearShopCue() {
    if (!shopCue) return;
    shopCue = false;
    const c = grid.querySelector('.prod.coach');
    if (c) { const t = c.querySelector('.coach-tip'); if (t) { t.classList.add('out'); setTimeout(() => t.remove(), 350); } c.classList.remove('coach'); }
  }
  setShopCue();

  function totalQty() { return Object.values(counts).reduce((a, b) => a + b, 0); }
  function totalPrice() { return products.reduce((s, p) => s + (counts[p.id] || 0) * p.pr, 0); }

  function renderCart(animateTotal) {
    const qty = totalQty();
    badge.textContent = qty;
    badge.classList.toggle('show', qty > 0);
    if (qty > 0 && !RM) { badge.classList.remove('pop'); void badge.offsetWidth; badge.classList.add('pop'); }

    const total = totalPrice();
    if (animateTotal) countUp(totalEl, total, inr, 500); else totalEl.textContent = inr(total);

    // free-shipping progress
    const pctv = Math.min(1, total / FREE_SHIP);
    shipFill.style.width = (pctv * 100) + '%';
    if (total >= FREE_SHIP) { shipMsg.textContent = 'free shipping unlocked ✓'; shipMsg.classList.add('ok'); shipFill.classList.add('ok'); }
    else { shipMsg.textContent = inr(FREE_SHIP - total) + ' away from free shipping'; shipMsg.classList.remove('ok'); shipFill.classList.remove('ok'); }

    const lines = products.filter(p => counts[p.id]);
    itemsEl.querySelectorAll('.ci').forEach(n => n.remove());
    emptyEl.style.display = lines.length ? 'none' : '';
    lines.forEach(p => {
      const li = document.createElement('div');
      li.className = 'ci';
      li.innerHTML = '<div class="img"><img src="' + IMG(p.img, 120) + '" alt="" /></div>' +
        '<div class="nm">' + p.nm + '<span>' + (sizeSel[p.id] ? 'size ' + sizeSel[p.id] + ' · ' : '') + inr(p.pr) + '</span></div>' +
